import React, { useState, useEffect, useCallback } from 'react';
import { Container, Card, Form, Button, Row, Col, Alert, Table } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const ExerciseLog = () => {
  const { token, authFetch } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    activity_type: '',
    duration_minutes: '',
    calories_burned: '',
  });
  const [activityPreset, setActivityPreset] = useState('Brisk Walking');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [logs, setLogs] = useState([]);

  const activityOptions = [
    'Brisk Walking',
    'Running',
    'Cycling',
    'Jump Rope',
    'Yoga / Mobility',
    'Stretching',
    'Strength Training',
    'Squats',
    'Push-ups',
    'Lunges',
    'Resistance Band Rows',
    'Custom…',
  ];

  const loadLogs = useCallback(async () => {
    const res = await authFetch('/api/exercise');
    if (res.status === 401) {
      navigate('/login');
      return;
    }
    const data = await res.json();
    if (!res.ok) {
      setError(data.error || 'Failed to load exercise');
      return;
    }
    setLogs(data.logs || []);
  }, [authFetch, navigate]);

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }
    loadLogs();
  }, [token, navigate, loadLogs]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handlePresetChange = (e) => {
    const value = e.target.value;
    setActivityPreset(value);
    if (value !== 'Custom…') {
      setForm((prev) => ({ ...prev, activity_type: value }));
    } else {
      setForm((prev) => ({ ...prev, activity_type: '' }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const body = {
        activity_type: form.activity_type.trim(),
        duration_minutes: parseInt(form.duration_minutes, 10),
      };
      if (form.calories_burned) {
        body.calories_burned = parseInt(form.calories_burned, 10);
      }
      const res = await authFetch('/api/exercise', {
        method: 'POST',
        body,
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || 'Could not log exercise');
        return;
      }
      setForm({ activity_type: '', duration_minutes: '', calories_burned: '' });
      await loadLogs();
    } catch {
      setError('Network error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container className="py-4">
      <h2 className="mb-4">Track exercise</h2>
      <Alert variant="info" className="mb-4">
        If you leave “Calories burned” blank, the app will estimate calories using your saved profile weight (after you generate a diet plan).
      </Alert>
      <Row>
        <Col md={5}>
          <Card className="mb-4">
            <Card.Body>
              <Card.Title>Log activity</Card.Title>
              {error && <Alert variant="danger">{error}</Alert>}
              <Form onSubmit={handleSubmit}>
                <Form.Group className="mb-3">
                  <Form.Label>Activity</Form.Label>
                  <Form.Select value={activityPreset} onChange={handlePresetChange} className="mb-2">
                    {activityOptions.map((opt) => (
                      <option key={opt} value={opt}>
                        {opt}
                      </option>
                    ))}
                  </Form.Select>
                  {activityPreset === 'Custom…' && (
                    <Form.Control
                      name="activity_type"
                      value={form.activity_type}
                      onChange={handleChange}
                      placeholder="Type your activity (e.g. Swimming)"
                      required
                    />
                  )}
                </Form.Group>
                <Form.Group className="mb-3">
                  <Form.Label>Duration (minutes)</Form.Label>
                  <Form.Control
                    name="duration_minutes"
                    type="number"
                    min="1"
                    value={form.duration_minutes}
                    onChange={handleChange}
                    required
                  />
                </Form.Group>
                <Form.Group className="mb-3">
                  <Form.Label>Calories burned (optional)</Form.Label>
                  <Form.Control
                    name="calories_burned"
                    type="number"
                    min="0"
                    value={form.calories_burned}
                    onChange={handleChange}
                  />
                </Form.Group>
                <Button type="submit" disabled={loading}>
                  {loading ? 'Saving…' : 'Log exercise'}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>
        <Col md={7}>
          <Card>
            <Card.Body>
              <Card.Title>Recent sessions</Card.Title>
              <Table size="sm" responsive hover>
                <thead>
                  <tr>
                    <th>When</th>
                    <th>Activity</th>
                    <th>Min</th>
                    <th>Cal</th>
                  </tr>
                </thead>
                <tbody>
                  {logs.length === 0 ? (
                    <tr>
                      <td colSpan={4} className="text-muted">
                        No sessions logged
                      </td>
                    </tr>
                  ) : (
                    logs.map((row) => (
                      <tr key={row.id}>
                        <td>{new Date(row.logged_at).toLocaleString()}</td>
                        <td>{row.activity_type}</td>
                        <td>{row.duration_minutes}</td>
                        <td>{row.calories_burned ?? '—'}</td>
                      </tr>
                    ))
                  )}
                </tbody>
              </Table>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
};

export default ExerciseLog;
